module RefModule(  
    input [71:0] matrix,  
    output reg [7:0] median  
);  
    reg [7:0] obf_values [0:8];  
    integer i, j;  

    always @(*) begin  
        // Convert input to an array  
        for (i = 0; i < 9; i = i + 1) begin  
            obf_values[i] = matrix[8*i +: 8];  
        end  

        // Simple bubble sort to find the median  
        for (i = 0; i < 8; i = i + 1) begin  
            for (j = i + 1; j < 9; j = j + 1) begin  
                if (obf_values[i] > obf_values[j]) begin  
                    // Swap  
                    {obf_values[i], obf_values[j]} = {obf_values[j], obf_values[i]};  
                end  
            end  
        end  

        // The median is the 5th element in the sorted array  
        median = obf_values[4];  
    end  
endmodule
